import{_ as d,o as a,c as r,ag as e}from"./chunks/framework.DEs8X8sU.js";const P=JSON.parse('{"title":"はじめに","description":"","frontmatter":{"title":"はじめに"},"headers":[],"relativePath":"tenant/01-introduction.md","filePath":"tenant/01-introduction.md"}'),i={name:"tenant/01-introduction.md"};function o(l,t,n,h,s,c){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="_1-はじめに" tabindex="-1">1. はじめに <a class="header-anchor" href="#_1-はじめに" aria-label="Permalink to &quot;1. はじめに&quot;">​</a></h1><p>POSLAは、飲食店の注文受付、キッチン連携、会計、スタッフ管理、レポート確認をまとめて行うクラウド型システムです。お客様はテーブルのQRコードから注文し、店舗スタッフは管理画面、ハンディ、KDS、レジ画面を使って営業を進めます。</p><h2 id="poslaでできること" tabindex="-1">POSLAでできること <a class="header-anchor" href="#poslaでできること" aria-label="Permalink to &quot;POSLAでできること&quot;">​</a></h2><ul><li>セルフオーダー、ハンディPOS、テイクアウト、予約の受付</li><li>KDSによる厨房への注文共有</li><li>POSレジでの会計、領収書、返金対応</li><li>メニュー、テーブル、フロアマップ、在庫、シフトの管理</li><li>売上、回転率、スタッフ評価、ABC分析などのレポート確認</li><li>AIアシスタントによる投稿文作成、売上分析、需要予測、ヘルプ確認</li></ul><h2 id="推奨環境" tabindex="-1">推奨環境 <a class="header-anchor" href="#推奨環境" aria-label="Permalink to &quot;推奨環境&quot;">​</a></h2><p>POSLAの店舗業務端末（KDS・レジ・ハンディ）は、<strong>Android端末のGoogle Chrome最新版</strong> でのご利用を <strong>標準環境</strong> としています。管理画面はPCまたはAndroid端末のChrome/Edgeで快適に操作できます。</p><table tabindex="0"><thead><tr><th>用途</th><th>標準環境</th><th>推奨環境</th><th>サポート対象外</th></tr></thead><tbody><tr><td>管理画面</td><td>PC + Chrome最新版</td><td>PC + Edge最新版 / Androidタブレット + Chrome</td><td>Internet Explorer・古いブラウザ</td></tr><tr><td>KDS</td><td>Androidタブレット（10インチ以上）+ Chrome最新版</td><td>—</td><td>iPad/Safari、Fireタブレット、独自ブラウザ</td></tr><tr><td>POSレジ</td><td>Androidタブレット + Chrome最新版</td><td>PC + Chrome最新版</td><td>iPad/Safari、Fireタブレット</td></tr><tr><td>ハンディPOS</td><td>Androidスマホ/タブレット + Chrome最新版</td><td>—</td><td>iPhone/Safari、Fireタブレット</td></tr><tr><td>お客様のセルフオーダー</td><td>お客様のスマートフォン（iPhone/Android問わず）</td><td>主要ブラウザ全般（Safari/Chrome等）</td><td>—</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">顧客セルフメニューはブラウザ自由</p><p>お客様がQRから利用するセルフメニュー、予約、テイクアウト画面はブラウザを限定しません。お手持ちのスマートフォンでそのままご利用いただけます。</p></div><div class="warning custom-block"><p class="custom-block-title">業務端末でiPad/Safariを使う場合の制限</p><p>iPad/Safariでも一部画面は表示できますが、KDSの音声コマンドや通知音、PWAインストール導線は安定して動作しません。安定運用を希望される場合はAndroid端末のChrome最新版をご利用ください。</p></div><p>店舗のWi-Fiが不安定な場合、注文送信や画面更新が遅れることがあります。</p><h2 id="ロールの違い" tabindex="-1">ロールの違い <a class="header-anchor" href="#ロールの違い" aria-label="Permalink to &quot;ロールの違い&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ロール</th><th>主な利用者</th><th>できること</th></tr></thead><tbody><tr><td>オーナー</td><td>経営者・本部担当者</td><td>全店舗の管理、ユーザー管理、複数店舗レポート、契約・決済設定</td></tr><tr><td>マネージャー</td><td>店長・責任者</td><td>担当店舗のメニュー、注文、会計、在庫、シフト、レポート管理</td></tr><tr><td>スタッフ</td><td>ホール・キッチン担当</td><td>勤怠打刻、シフト確認、希望シフト提出など</td></tr><tr><td>端末専用アカウント</td><td>KDS・レジ・ハンディ端末</td><td>店舗備品端末での業務利用</td></tr></tbody></table><p>POSLAでは、全スタッフに個別アカウントを作成してください。共有アカウントを使うと、勤怠、監査ログ、スタッフ評価で「誰が操作したか」を正しく記録できません。</p><h2 id="ご契約プラン" tabindex="-1">ご契約プラン <a class="header-anchor" href="#ご契約プラン" aria-label="Permalink to &quot;ご契約プラン&quot;">​</a></h2><p>POSLA は <strong>単一プラン + 任意アドオン</strong> の構成です。すべての機能（セルフオーダー、ハンディPOS、KDS、POSレジ、テイクアウト、予約、在庫、シフト、AIアシスタント、多言語、レポート、決済連携など）はすべての契約者に標準提供されます。</p><table tabindex="0"><thead><tr><th>項目</th><th>月額</th></tr></thead><tbody><tr><td>基本料金（1店舗目）</td><td>¥20,000</td></tr><tr><td>追加店舗（2店舗目以降）</td><td>¥17,000 / 店舗（15%引き）</td></tr><tr><td>本部一括メニュー配信アドオン（任意）</td><td>+¥3,000 / 店舗</td></tr></tbody></table><p><strong>お試し利用：</strong> 初回ご契約から <strong>30日間無料</strong>。期間中に解約された場合は課金されません。31日目から自動で月額課金が開始されます（カード登録は契約時に必要）。</p><p>ご契約内容の確認・店舗追加・アドオンのオンオフは、オーナーダッシュボードの「契約・お支払い」から操作できます。詳しい手順は <a href="/public/docs-internal/operations/part7-billing.html">Part 7: 契約・お支払い</a> をご覧ください。</p><h2 id="導入時の基本順序" tabindex="-1">導入時の基本順序 <a class="header-anchor" href="#導入時の基本順序" aria-label="Permalink to &quot;導入時の基本順序&quot;">​</a></h2><ol><li>オーナーアカウントでログインします。</li><li>店舗情報、営業時間、税率、支払い方法を設定します。</li><li>スタッフアカウントと端末専用アカウントを作成します。</li><li>メニュー、テーブル、フロアマップを登録します。</li><li>KDS、レジ、プリンタ、決済端末を確認します。</li><li>テスト注文とテスト会計を行います。</li><li>問題がなければ、お客様用QRコードを掲示します。</li></ol><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><p>まずは画面に表示されたメッセージ、操作した画面名、発生時刻を控えてください。管理画面右下のAIヘルプデスク、またはPOSLAサポートにご連絡いただくと確認がスムーズです。</p>',22)])])}const b=d(i,[["render",o]]);export{P as __pageData,b as default};
